#include <math.h>
#include <omp.h>

#include "./main.h"
#include "./kernel/kernel_cpu.h"

void kernel_cpu(par_str par,
                dim_str dim,
                box_str* box,
                FOUR_VECTOR* rv,
                fp* qv,
                FOUR_VECTOR* fv) {
    long bx;

    #pragma omp parallel for num_threads(dim.cores_arg) schedule(static)
    for (bx = 0; bx < dim.number_boxes; bx++) {
        FOUR_VECTOR rA_shared[NUMBER_PAR_PER_BOX];
        FOUR_VECTOR rB_shared[NUMBER_PAR_PER_BOX];
        fp qB_shared[NUMBER_PAR_PER_BOX];

        fp a2 = (fp)2.0 * par.alpha * par.alpha;
        int first_i = (int)box[bx].offset;

        for (int i = 0; i < NUMBER_PAR_PER_BOX; i++) {
            rA_shared[i] = rv[first_i + i];
        }

        for (int k = 0; k < (1 + box[bx].nn); k++) {
            int pointer = (k == 0) ? (int)bx : box[bx].nei[k - 1].number;
            int first_j = (int)box[pointer].offset;

            for (int j = 0; j < NUMBER_PAR_PER_BOX; j++) {
                rB_shared[j] = rv[first_j + j];
                qB_shared[j] = qv[first_j + j];
            }

            for (int i = 0; i < NUMBER_PAR_PER_BOX; i++) {
                fp sum_v = 0;
                fp sum_x = 0;
                fp sum_y = 0;
                fp sum_z = 0;

                FOUR_VECTOR rAi = rA_shared[i];

                for (int j = 0; j < NUMBER_PAR_PER_BOX; j++) {
                    fp r2 = rAi.v + rB_shared[j].v - DOT(rAi, rB_shared[j]);
                    fp u2 = a2 * r2;
                    fp vij = exp(-u2);
                    fp fs = (fp)2.0 * vij;

                    fp dx = rAi.x - rB_shared[j].x;
                    fp dy = rAi.y - rB_shared[j].y;
                    fp dz = rAi.z - rB_shared[j].z;

                    fp q = qB_shared[j];
                    sum_v += q * vij;
                    sum_x += q * (fs * dx);
                    sum_y += q * (fs * dy);
                    sum_z += q * (fs * dz);
                }

                fv[first_i + i].v += sum_v;
                fv[first_i + i].x += sum_x;
                fv[first_i + i].y += sum_y;
                fv[first_i + i].z += sum_z;
            }
        }
    }
}
